// دالة محسنة لحساب تشابه النصوص
function calculateTextSimilarity(text1, text2) {
  if (!text1 || !text2) return 0;

  const normalize = (str) => str.toLowerCase().replace(/[^\w\sء-ي]/g, '').trim();
  const norm1 = normalize(text1);
  const norm2 = normalize(text2);

  if (norm1 === norm2) return 1;

  // حساب Levenshtein distance
  const matrix = [];
  for (let i = 0; i <= norm2.length; i++) {
    matrix[i] = [i];
  }
  for (let j = 0; j <= norm1.length; j++) {
    matrix[0][j] = j;
  }
  for (let i = 1; i <= norm2.length; i++) {
    for (let j = 1; j <= norm1.length; j++) {
      if (norm2.charAt(i - 1) === norm1.charAt(j - 1)) {
        matrix[i][j] = matrix[i - 1][j - 1];
      } else {
        matrix[i][j] = Math.min(
          matrix[i - 1][j - 1] + 1,
          matrix[i][j - 1] + 1,
          matrix[i - 1][j] + 1
        );
      }
    }
  }

  const distance = matrix[norm2.length][norm1.length];
  const maxLength = Math.max(norm1.length, norm2.length);
  return 1 - (distance / maxLength);
}

// دالة محسنة لدمج النصوص المتعددة
function mergeMessageTexts(messageTexts) {
  if (!messageTexts || messageTexts.length === 0) return '';

  // إذا كان نص واحد فقط
  if (messageTexts.length === 1) {
    return messageTexts[0].text || messageTexts[0];
  }

  // ترتيب النصوص حسب الأولوية والوقت
  const sortedTexts = messageTexts.sort((a, b) => {
    // إذا كان كائن بمعلومات إضافية
    if (typeof a === 'object' && typeof b === 'object') {
      if (b.priority !== a.priority) return b.priority - a.priority;
      return b.timestamp - a.timestamp;
    }
    return 0;
  });

  // استخراج النصوص الفعلية
  const texts = sortedTexts.map(item => 
    typeof item === 'string' ? item : item.text || ''
  ).filter(text => text && text.trim());

  if (texts.length === 0) return '';

  // إزالة النصوص المكررة أو المتشابهة جداً
  const uniqueTexts = [];
  for (const text of texts) {
    const isDuplicate = uniqueTexts.some(existing => 
      calculateTextSimilarity(existing, text) > CONFIG.TEXT_MERGE_THRESHOLD
    );
    if (!isDuplicate) {
      uniqueTexts.push(text);
    }
  }

  // إذا كان هناك نص واحد فريد فقط
  if (uniqueTexts.length === 1) {
    return uniqueTexts[0];
  }

  // البحث عن النص الأكثر شمولية
  let mostComprehensive = uniqueTexts[0];
  for (const text of uniqueTexts) {
    // النص الأطول غالباً ما يكون الأكثر شمولية
    if (text.length > mostComprehensive.length) {
      // تحقق من أن النص الأطول يحتوي على معلومات مفيدة
      const hasMoreInfo = text.split(/\s+/).length > mostComprehensive.split(/\s+/).length * 1.2;
      if (hasMoreInfo) {
        mostComprehensive = text;
      }
    }
  }

  // إذا كانت النصوص مختلفة تماماً، دمجها
  const similarity = calculateTextSimilarity(uniqueTexts[0], uniqueTexts[uniqueTexts.length - 1]);
  if (similarity < 0.5 && uniqueTexts.length <= 3) {
    // دمج النصوص المختلفة كمحادثة
    return uniqueTexts.join(' | ');
  }

  return mostComprehensive;
}

// دالة محسنة لحساب درجة الاكتمال
function calculateCompleteness(data, group) {
  let score = 0;
  const weights = CONFIG.COMPLETENESS_WEIGHTS;

  // تقييم وجود النص
  if (data.message_text && data.message_text.trim().length > 2) {
    const textQuality = Math.min(100, data.message_text.length / 2);
    score += weights.has_text * (textQuality / 100);
  }

  // تقييم معلومات Pipeline
  if (data.pipeline_id || data.pipeline?.id) {
    score += weights.has_pipeline;
    // نقاط إضافية إذا كان Pipeline معروف
    if (PIPELINE_CONFIG[data.pipeline_id || data.pipeline?.id]) {
      score += 5;
    }
  }

  // تقييم معلومات Stage
  if (data.stage_id || data.stage?.id) {
    score += weights.has_stage;
    // نقاط إضافية للتحولات
    if (data.stage_changed || data.stage?.changed) {
      score += 5;
    }
  }

  // تقييم معرف Lead
  if (data.lead_id) {
    score += weights.has_lead_id;
  }

  // تقييم Tags
  if (data.tags && data.tags.length > 0) {
    const tagScore = Math.min(weights.has_tags, data.tags.length * 2);
    score += tagScore;
  }

  // تقييم عدد النبضات
  const pulseScore = Math.min(weights.pulse_count, 
    (group.total_pulses / (data.expected_pulses || 4)) * weights.pulse_count
  );
  score += pulseScore;

  // نقاط إضافية للبيانات المكملة
  if (data.client_name) score += 3;
  if (data.chat_id || data.conversation_id) score += 3;
  if (data.entity_id) score += 2;
  if (data.message_id) score += 2;

  return Math.min(100, Math.round(score));
}

// دالة محسنة لتحديد مستوى الثقة
function determineConfidenceLevel(completeness, validation, hasMultipleSources) {
  // الثقة العالية
  if (completeness >= 85 && validation.isValid && hasMultipleSources) {
    return 'very_high';
  }
  if (completeness >= 75 && validation.isValid) {
    return 'high';
  }

  // الثقة المتوسطة
  if (completeness >= 60 || (validation.isValid && completeness >= 50)) {
    return 'medium';
  }

  // الثقة المنخفضة
  if (completeness >= 40 || validation.isValid) {
    return 'low';
  }

  return 'very_low';
}

// دالة لحساب الأولوية النهائية المحسنة
function calculateFinalPriority(intervention, completeness, hasMessage, tags) {
  let priorityScore = CONFIG.PRIORITY_WEIGHT[intervention.priority] || 50;

  // تعديل بناءً على الاكتمال
  if (completeness < 50) {
    priorityScore *= 0.7;
  } else if (completeness >= 90) {
    priorityScore *= 1.3;
  } else if (completeness >= 75) {
    priorityScore *= 1.1;
  }

  // زيادة الأولوية للرسائل
  if (hasMessage) {
    priorityScore += 15;
  }

  // زيادة للتدخل البشري
  if (intervention.requires_human) {
    priorityScore += 30;
  }

  // زيادة لـ AI Agent
  if (intervention.use_ai_agent) {
    priorityScore += 10;
  }

  // تعديل بناءً على Tags
  if (tags && tags.length > 0) {
    if (tags.includes('urgent') || tags.includes('emergency')) {
      priorityScore += 25;
    }
    if (tags.includes('vip') || tags.includes('premium')) {
      priorityScore += 20;
    }
    if (tags.includes('complaint') || tags.includes('escalation')) {
      priorityScore += 15;
    }
  }

  // تحديد الأولوية النهائية
  if (priorityScore >= 90) return 'critical';
  if (priorityScore >= 65) return 'high';
  if (priorityScore >= 40) return 'normal';
  return 'low';
}

// دالة محسنة لتحديد نوع الاستجابة
function determineResponseType(data, confidence, completeness) {
  const response = {
    type: 'none',
    method: 'none',
    delay: 0,
    template: null,
    confidence_required: 'medium'
  };

  // إذا لا يوجد محتوى صالح
  if (!data.has_valid_content && !data.is_new_lead && !data.stage?.changed) {
    response.type = 'log_only';
    response.method = 'store';
    return response;
  }

  // تحديد بناءً على التدخل المطلوب
  if (data.intervention) {
    if (data.intervention.requires_human) {
      response.type = 'human_escalation';
      response.method = 'notify_team';
      response.delay = 0;
      response.template = 'escalation_required';
      response.confidence_required = 'low'; // التصعيد لا يحتاج ثقة عالية
    } else if (data.intervention.use_ai_agent) {
      // تحديد مستوى AI بناءً على الثقة
      if (confidence === 'very_high' || confidence === 'high') {
        response.type = 'ai_response';
        response.method = 'ai_agent_full';
        response.delay = 1500;
        response.template = 'ai_contextual';
      } else if (confidence === 'medium' && completeness >= CONFIG.MIN_CONFIDENCE_FOR_AI) {
        response.type = 'ai_response_guided';
        response.method = 'ai_agent_supervised';
        response.delay = 3000;
        response.template = 'ai_with_confirmation';
      } else {
        response.type = 'ai_with_fallback';
        response.method = 'ai_agent_limited';
        response.delay = 5000;
        response.template = 'ai_safe_mode';
        response.confidence_required = 'high';
      }
    } else {
      // البوت العادي
      if (completeness >= CONFIG.MIN_CONFIDENCE_FOR_BOT && confidence !== 'very_low') {
        response.type = 'bot_response';
        response.method = 'standard_bot';
        response.delay = 1000;
        response.template = 'bot_standard';
      } else {
        response.type = 'queue_for_review';
        response.method = 'add_to_queue';
        response.delay = 0;
        response.template = 'queued';
      }
    }
  }

  // تعديلات خاصة بناءً على السياق
  if (data.is_new_lead) {
    if (response.type === 'none' || response.type === 'log_only') {
      response.type = 'welcome_message';
      response.method = 'send_welcome';
      response.delay = 500;
      response.template = 'welcome_new_lead';
    }
  }

  if (data.stage?.changed && PIPELINE_CONFIG[data.pipeline?.id]) {
    const config = PIPELINE_CONFIG[data.pipeline.id];
    if (config.auto_escalate_stages?.includes(data.stage.id)) {
      response.type = 'auto_escalation';
      response.method = 'escalate_to_team';
      response.delay = 0;
    }
  }

  // تعديل بناءً على Tags الحرجة
  if (data.tags?.includes('emergency')) {
    response.delay = 0;
    if (response.type === 'bot_response') {
      response.type = 'ai_response';
      response.method = 'ai_agent_emergency';
    }
  }

  return response;
}

// دالة للتحقق من صحة المحتوى - محسنة
function validateMessageContent(text) {
  if (!text || text.trim() === '') {
    return {
      isValid: false,
      reason: 'empty_text',
      confidence: 0,
      quality: 'none'
    };
  }

  const trimmed = text.trim();

  // فحوصات الرفض
  if (/^\d+$/.test(trimmed)) {
    return {
      isValid: false,
      reason: 'numbers_only',
      confidence: 0,
      quality: 'invalid'
    };
  }

  if (trimmed.length < CONFIG.TEXT_PROCESSING.min_length) {
    return {
      isValid: false,
      reason: 'too_short',
      confidence: 0,
      quality: 'invalid'
    };
  }

  if (!/[a-zA-Zء-ي]/.test(trimmed)) {
    return {
      isValid: false,
      reason: 'no_letters',
      confidence: 0,
      quality: 'invalid'
    };
  }

  // فحوصات URLs وغيرها
  if (/^https?:\/\//.test(trimmed) && trimmed.split(/\s+/).length <= 3) {
    return {
      isValid: false,
      reason: 'url_only',
      confidence: 0,
      quality: 'invalid'
    };
  }

  // تقييم جودة النص
  let quality = 'low';
  let confidence = 60;

  if (trimmed.length > 20) {
    quality = 'medium';
    confidence = 80;
  }

  if (trimmed.length > 50 && trimmed.split(/\s+/).length > 5) {
    quality = 'high';
    confidence = 95;
  }

  if (trimmed.length > 100 && trimmed.split(/\s+/).length > 10) {
    quality = 'excellent';
    confidence = 100;
  }

  return {
    isValid: true,
    reason: 'valid',
    confidence,
    quality,
    length: trimmed.length,
    word_count: trimmed.split(/\s+/).length
  };
}

// دالة لتحديد القناة - محسنة
function determineResponseChannel(data) {
  // تحديد من platform إذا كان موجود
  if (data.platform) {
    const platformMap = {
      'whatsapp': 'whatsapp',
      'instagram': 'instagram',
      'facebook': 'messenger',
      'telegram': 'telegram',
      'webchat': 'webchat'
    };
    if (platformMap[data.platform]) {
      return platformMap[data.platform];
    }
  }

  // تحديد من source
  const source = (data.source || '').toLowerCase();
  if (source.includes('waba') || source.includes('whatsapp')) return 'whatsapp';
  if (source.includes('instagram') || source.includes('ig')) return 'instagram';
  if (source.includes('facebook') || source.includes('fb')) return 'messenger';
  if (source.includes('telegram') || source.includes('tg')) return 'telegram';
  if (source.includes('web')) return 'webchat';

  // تحديد من chat_id
  if (data.chat_id) {
    if (data.chat_id.includes('wa')) return 'whatsapp';
    if (data.chat_id.includes('ig')) return 'instagram';
    if (data.chat_id.includes('fb')) return 'messenger';
    if (data.chat_id.includes('tg')) return 'telegram';
  }

  // تحديد من response_channel إذا كان موجود
  if (data.response_channel) {
    return data.response_channel;
  }

  return 'unknown';
}

// دالة محسنة لبناء سياق AI
function buildAIContext(data, validation, completeness) {
  const context = {
