      action_required: data.action_required
    },
    instructions: {
      tone: 'professional_friendly',
      language: data.intervention?.language || 'ar',
      max_length: 500,
      include_cta: true,
      response_format: 'conversational',
      use_emojis: false,
      personalization_level: 'medium'
    }
  };

  // تخصيص التعليمات بناءً على السياق
  if (data.is_new_lead) {
    context.instructions.greeting_type = 'warm_welcome';
    context.instructions.introduce_services = true;
