    context.instructions.ask_for_clarification = true;
    context.instructions.suggest_options = true;
  }

  // تعديل بناءً على القناة
  if (context.conversation.channel === 'whatsapp') {
    context.instructions.format_for_whatsapp = true;
    context.instructions.use_whatsapp_formatting = true;
  }

  return context;
}

// دالة لإعادة بناء تدفق المحادثة
function reconstructConversationFlow(group) {
  const flow = {
    events_timeline: [],
    text_sequence: [],
    stage_transitions: [],
    has_coherent_flow: false,
    conversation_type: 'unknown'
  };

  // بناء خط زمني للأحداث
  if (group.items && group.items.length > 0) {
    group.items.forEach(item => {
      const data = item.json;
      flow.events_timeline.push({
        event_type: data.event_types || data.event_type || 'unknown',
        timestamp: data.event_time_utc || data.created_at,
        has_text: !!data.message_text,
        text_preview: data.message_text ? data.message_text.substring(0, 50) : '',
        stage: data.stage_id || data.stage?.id,
        pipeline: data.pipeline_id || data.pipeline?.id
      });
    });

    // ترتيب الأحداث زمنياً
    flow.events_timeline.sort((a, b) => 
      new Date(a.timestamp) - new Date(b.timestamp)
    );
  }

  // استخراج تسلسل النصوص
  if (group.message_texts && group.message_texts.length > 0) {
    flow.text_sequence = group.message_texts.map(msg => ({
      text: typeof msg === 'string' ? msg : msg.text,
      source: typeof msg === 'object' ? msg.event_type : 'unknown',
      priority: typeof msg === 'object' ? msg.priority : 0
    }));
  }

  // تتبع تحولات المراحل
  const stages = new Set();
  group.items.forEach(item => {
    const stageId = item.json.stage_id || item.json.stage?.id;
    if (stageId) stages.add(stageId);
  });
  flow.stage_transitions = Array.from(stages);

  // تحديد نوع المحادثة
  if (group.items.some(item => item.json.is_new_lead)) {
    flow.conversation_type = 'new_lead';
  } else if (flow.stage_transitions.length > 1) {
    flow.conversation_type = 'progressing';
  } else if (flow.text_sequence.length > 0) {
    flow.conversation_type = 'ongoing';
  }

  // تقييم تماسك التدفق
  flow.has_coherent_flow = (
    flow.events_timeline.length > 0 &&
    (flow.text_sequence.length > 0 || flow.conversation_type === 'new_lead')
  );

  return flow;
}

