const staticData = $getWorkflowStaticData('global');
const messageGroups = {};

debugLog("=== Starting Enhanced Message Completeness Check ===");
debugLog(`Processing ${items.length} items`);

// تجميع كل الرسائل حسب fingerprint مع معالجة محسنة
items.forEach((item, index) => {
  const fingerprint = item.json.message_fingerprint || item.json.group_key;

  if (!fingerprint) {
    debugLog(`Warning: Item ${index} without fingerprint`, item.json);
    return;
  }

  if (!messageGroups[fingerprint]) {
    messageGroups[fingerprint] = {
      items: [],
      total_pulses: 0,
      expected_pulses: 0,
      latest_data: null,
      highest_priority: null,
      all_tags: new Set(),
      all_stages: new Set(),
      all_pipelines: new Set(),
      message_texts: [],
      all_texts: [],
      validation_results: [],
      event_types: new Set(),
      has_multiple_sources: false,
      first_timestamp: null,
      last_timestamp: null
    };
  }

  const group = messageGroups[fingerprint];
  group.items.push(item);

  // تحديث عدد النبضات
  group.total_pulses += item.json.pulses_received || 1;
  group.expected_pulses = Math.max(
    group.expected_pulses, 
    item.json.expected_pulses || 0
  );

  // تحديث التوقيتات
  const timestamp = item.json.event_time_utc || item.json.created_at;
  if (timestamp) {
    if (!group.first_timestamp || timestamp < group.first_timestamp) {
      group.first_timestamp = timestamp;
    }
    if (!group.last_timestamp || timestamp > group.last_timestamp) {
      group.last_timestamp = timestamp;
    }
  }

  // جمع كل النصوص مع معلومات إضافية
  if (item.json.message_text && item.json.message_text.trim() !== '') {
    const validation = validateMessageContent(item.json.message_text);
    group.message_texts.push({
      text: item.json.message_text,
      event_type: item.json.event_types || item.json.event_type || 'unknown',
      priority: item.json.priority || 0,
      timestamp: timestamp,
      validation: validation,
      source_index: index
    });
    group.validation_results.push(validation);
  }

  // جمع كل النصوص من debug_info إذا كانت موجودة
  if (item.json.debug_info?.all_texts) {
    const debugTexts = item.json.debug_info.all_texts.split(" | ");
    debugTexts.forEach(text => {
      if (text && text.trim()) {
        group.all_texts.push(text.trim());
      }
    });
  }

  // جمع Tags من كل النبضات
  if (item.json.tags && Array.isArray(item.json.tags)) {
    item.json.tags.forEach(tag => group.all_tags.add(tag));
  }
  if (item.json.all_tags_collected) {
    item.json.all_tags_collected.forEach(tag => group.all_tags.add(tag));
  }

  // تتبع المراحل والـ Pipelines
  if (item.json.stage_id || item.json.stage?.id) {
    group.all_stages.add(item.json.stage_id || item.json.stage.id);
  }
  if (item.json.pipeline_id || item.json.pipeline?.id) {
    group.all_pipelines.add(item.json.pipeline_id || item.json.pipeline.id);
  }

  // جمع أنواع الأحداث
  if (item.json.event_types) {
    item.json.event_types.split(',').forEach(type => 
      group.event_types.add(type.trim())
    );
  }
  if (item.json.unique_events) {
    item.json.unique_events.forEach(type => group.event_types.add(type));
  }

  // تحديد إذا كان هناك مصادر متعددة
  if (group.event_types.size > 1) {
    group.has_multiple_sources = true;
  }

  // احتفظ بأحدث البيانات الأكثر اكتمالاً
  const currentData = group.latest_data;
  const newData = item.json;

  if (!currentData || 
      newData.completeness_percentage > (currentData.completeness_percentage || 0) ||
      newData.pulses_received > (currentData.pulses_received || 0) ||
      (newData.message_text && !currentData.message_text) ||
      (newData.pipeline_id && !currentData.pipeline_id) ||
      (newData.lead_id && !currentData.lead_id)) {
    group.latest_data = newData;
  }

  // تتبع أعلى أولوية
  if (newData.intervention?.priority || newData.final_priority) {
    const priority = newData.final_priority || newData.intervention.priority;
    const priorities = ['low', 'normal', 'high', 'critical'];
    const currentPriorityIndex = priorities.indexOf(group.highest_priority || 'low');
    const newPriorityIndex = priorities.indexOf(priority);

    if (newPriorityIndex > currentPriorityIndex) {
      group.highest_priority = priority;
    }
  }
});

debugLog(`Found ${Object.keys(messageGroups).length} unique message groups`);

// ==================
// إنتاج النتائج النهائية المحسنة
// ==================
const finalMessages = [];

for (const [fingerprint, group] of Object.entries(messageGroups)) {
  const data = group.latest_data;

  if (!data) {
    debugLog(`Warning: No data for fingerprint ${fingerprint}`);
    continue;
  }

  // دمج النصوص بالطريقة المحسنة
  let bestMessageText = '';
  if (group.message_texts.length > 0 || group.all_texts.length > 0) {
    // دمج كل النصوص المتاحة
    const allAvailableTexts = [
      ...group.message_texts,
      ...group.all_texts.map(text => ({ text, priority: 0, event_type: 'extracted' }))
    ];

    bestMessageText = mergeMessageTexts(allAvailableTexts);
  }

  // إذا لم نجد نص، استخدم النص من البيانات الأصلية
  if (!bestMessageText && data.message_text) {
    bestMessageText = data.message_text;
  }

  // التحقق من صحة النص النهائي
  const finalValidation = validateMessageContent(bestMessageText);

  debugLog(`\n=== Processing Enhanced Group: ${fingerprint} ===`);
  debugLog(`Final message text: "${bestMessageText?.substring(0, 100)}..."`);
  debugLog(`Text validation:`, finalValidation);
  debugLog(`Total pulses: ${group.total_pulses}`);
  debugLog(`Event types: ${Array.from(group.event_types).join(', ')}`);
  debugLog(`Tags collected: ${Array.from(group.all_tags).join(', ')}`);
  debugLog(`Stages found: ${Array.from(group.all_stages).join(', ')}`);
  debugLog(`Has multiple sources: ${group.has_multiple_sources}`);

  // إعادة بناء تدفق المحادثة
  const conversationFlow = reconstructConversationFlow(group);

  // تحديث البيانات المجمعة
  if (group.all_tags.size > 0) {
    data.tags = Array.from(group.all_tags);
  }

  // حساب الاكتمال المحسن
  const completeness = calculateCompleteness(
    {...data, message_text: bestMessageText}, 
    group
  );

  // تحديد مستوى الثقة المحسن
  const confidence_level = determineConfidenceLevel(
    completeness,
    finalValidation,
    group.has_multiple_sources
  );

  // تحديد معلومات Pipeline/Stage النهائية
  let finalPipeline = data.pipeline || {};
  let finalStage = data.stage || {};

  // إذا كان هناك pipelines متعددة، اختر الأحدث
  if (group.all_pipelines.size > 0) {
    const pipelineId = Array.from(group.all_pipelines)[group.all_pipelines.size - 1];
    if (PIPELINE_CONFIG[pipelineId]) {
      finalPipeline = {
        id: pipelineId,
        name: PIPELINE_CONFIG[pipelineId].name,
        service: PIPELINE_CONFIG[pipelineId].service
      };
    }
  }

  // بناء تاريخ المراحل
  const stagesHistory = Array.from(group.all_stages).join(' → ') || 
                        data.stages_history || 
                        '';

  // التحقق من صلاحية البيانات
  const hasValidContent = !!(
    finalValidation.isValid || 
    data.is_new_lead || 
    data.stage_changed ||
    conversationFlow.has_coherent_flow ||
    (data.lead_id && data.action_required !== 'ignore')
  );

  // تحديد نوع الاستجابة المحسن
  const responseStrategy = determineResponseType(
    {...data, has_valid_content: hasValidContent},
    confidence_level,
    completeness
  );

  // تحديد الأولوية النهائية المحسنة
  const finalPriority = calculateFinalPriority(
    data.intervention || { priority: group.highest_priority || 'normal' },
    completeness,
    finalValidation.isValid,
    Array.from(group.all_tags)
  );

  // بناء سياق AI المحسن
  let aiContext = null;
  if (responseStrategy.method.includes('ai')) {
    aiContext = buildAIContext(
      {...data, message_text: bestMessageText, tags: Array.from(group.all_tags)},
      finalValidation,
      completeness
    );
  }

  // تحديد القناة النهائية
  const responseChannel = determineResponseChannel(data);

  // تحديد الإجراء المطلوب النهائي
  let action_required = data.action_required || 'log_only';
  let should_respond = data.should_respond || false;

  // تعديل الإجراء بناءً على التحليل الشامل
  if (!finalValidation.isValid && !data.is_new_lead) {
    if (conversationFlow.conversation_type === 'new_lead') {
      action_required = 'welcome_despite_no_text';
      should_respond = true;
    } else if (completeness >= 60 && data.lead_id) {
      action_required = 'request_clarification';
      should_respond = true;
    } else {
      action_required = 'invalid_message';
      should_respond = false;
    }
  } else if (finalValidation.isValid) {
    if (!data.action_required || data.action_required === 'log_only') {
      action_required = 'process_message';
      should_respond = true;
    }
  }

  // بناء النتيجة النهائية الشاملة والمحسنة
  finalMessages.push({
    json: {
      // === البيانات الأساسية المحسنة ===
      ...data,

      // === النص والمحتوى المحسن ===
      message_text: bestMessageText,
      original_message_text: data.message_text || '',
      merged_texts_count: group.message_texts.length + group.all_texts.length,

      // === معلومات الصحة والجودة ===
      text_validation: finalValidation,
      has_valid_text: finalValidation.isValid,
      text_quality: finalValidation.quality || 'unknown',

      // === معلومات الاكتمال المحسنة ===
      final_pulse_count: group.total_pulses,
      expected_pulses: group.expected_pulses || data.expected_pulses || 1,
      completeness_score: completeness,
      completeness_percentage: completeness,
      confidence_level,
      confidence_factors: {
        has_text: finalValidation.isValid,
        has_pipeline: !!finalPipeline.id,
        has_stage: !!finalStage.id,
        has_lead_id: !!data.lead_id,
        has_multiple_sources: group.has_multiple_sources,
        pulse_ratio: group.total_pulses / (group.expected_pulses || 1)
      },

      // === معلومات Pipeline/Stage المحسنة ===
      pipeline: finalPipeline,
      stage: finalStage,
      stages_history: stagesHistory,
      all_pipelines: Array.from(group.all_pipelines),
      all_stages: Array.from(group.all_stages),

      // === Tags المحسنة ===
      tags: Array.from(group.all_tags),
      tags_count: group.all_tags.size,
      has_critical_tags: Array.from(group.all_tags).some(tag => 
        TAG_RULES.human_required.includes(tag) || 
        tag === 'urgent' || 
        tag === 'emergency'
      ),

      // === معلومات التدخل المحسنة ===
      intervention: {
        ...data.intervention,
        priority: finalPriority,
        confidence: confidence_level,
        completeness_based: true
      },

      // === استراتيجية الاستجابة المحسنة ===
      response_strategy: responseStrategy,
      response_channel: responseChannel,
      final_priority: finalPriority,

      // === سياق AI المحسن ===
      ai_context: aiContext,

      // === تدفق المحادثة ===
      conversation_flow: conversationFlow,

      // === معلومات الخدمة المحسنة ===
      service_type: finalPipeline.service || data.service_type || 'general',
      pipeline_name: finalPipeline.name || data.pipeline_name || 'Unknown',
      requires_human: responseStrategy.type === 'human_escalation',
      use_ai_agent: responseStrategy.method.includes('ai'),

      // === معلومات المعالجة النهائية ===
      action_required,
      should_respond,
      response_confidence_required: responseStrategy.confidence_required || 'medium',

      // === التوقيتات المحسنة ===
      aggregation_completed_at: new Date().toISOString(),
      processing_duration_ms: group.last_timestamp && group.first_timestamp ? 
        new Date(group.last_timestamp) - new Date(group.first_timestamp) : 0,
      response_delay_ms: responseStrategy.delay,

      // === الحالة النهائية ===
      ready_for_processing: true,
      deduplication_count: group.items.length,
      has_valid_content: hasValidContent,
      is_complete: completeness >= 75,

      // === معلومات التوجيه المحسنة ===
      routing: {
        destination: responseStrategy.type,
        method: responseStrategy.method,
        channel: responseChannel,
        priority: finalPriority,
        has_ai_context: !!aiContext,
        template: responseStrategy.template,
        requires_review: confidence_level === 'low' || confidence_level === 'very_low'
      },

      // === معلومات Debug المحسنة والشاملة ===
      debug_info: {
        // معلومات النص
        text_extracted: finalValidation.isValid,
        text_length: bestMessageText.length,
        text_word_count: bestMessageText.split(/\s+/).length,
        text_quality: finalValidation.quality || 'unknown',
        text_validation_reason: finalValidation.reason,

        // معلومات التجميع
        message_texts_found: group.message_texts.length,
        all_texts_found: group.all_texts.length,
        texts_merged: group.message_texts.length + group.all_texts.length > 1,
        merge_method: group.message_texts.length > 1 ? 'comprehensive' : 'single',

        // معلومات الأحداث
        event_types_found: Array.from(group.event_types),
        unique_events_count: group.event_types.size,
        has_multiple_sources: group.has_multiple_sources,

        // معلومات التقييم
        completeness_score: completeness,
        confidence_level,
        validation_results: group.validation_results,

        // معلومات التدفق
        conversation_type: conversationFlow.conversation_type,
        has_coherent_flow: conversationFlow.has_coherent_flow,
        events_count: conversationFlow.events_timeline.length,

        // الحالة النهائية
        extraction_status: finalValidation.isValid ? 'SUCCESS' : `INVALID: ${finalValidation.reason}`,
        processing_status: 'COMPLETE',
        ready_for_next_step: should_respond
      }
    }
  });

  // تنظيف من الذاكرة المؤقتة
  if (staticData.messageCache && staticData.messageCache[fingerprint]) {
    delete staticData.messageCache[fingerprint];
  }
}

// ==================
// الإحصائيات النهائية الشاملة
// ==================
const stats = {
  total_groups: Object.keys(messageGroups).length,
  final_messages: finalMessages.length,

  // إحصائيات النصوص
  text_stats: {
    valid: finalMessages.filter(m => m.json.has_valid_text).length,
    invalid: finalMessages.filter(m => !m.json.has_valid_text).length,
    merged: finalMessages.filter(m => m.json.merged_texts_count > 1).length,
    quality: {
      excellent: finalMessages.filter(m => m.json.text_quality === 'excellent').length,
      high: finalMessages.filter(m => m.json.text_quality === 'high').length,
      medium: finalMessages.filter(m => m.json.text_quality === 'medium').length,
      low: finalMessages.filter(m => m.json.text_quality === 'low').length,
      invalid: finalMessages.filter(m => m.json.text_quality === 'invalid').length
    }
  },

  // إحصائيات الأولوية
  priority_breakdown: {
    critical: finalMessages.filter(m => m.json.final_priority === 'critical').length,
    high: finalMessages.filter(m => m.json.final_priority === 'high').length,
    normal: finalMessages.filter(m => m.json.final_priority === 'normal').length,
    low: finalMessages.filter(m => m.json.final_priority === 'low').length
  },

  // إحصائيات التدخل
  intervention_breakdown: {
    ai_agent: finalMessages.filter(m => m.json.use_ai_agent).length,
    human: finalMessages.filter(m => m.json.requires_human).length,
    bot: finalMessages.filter(m => !m.json.use_ai_agent && !m.json.requires_human).length
  },

  // إحصائيات الثقة
  confidence_breakdown: {
    very_high: finalMessages.filter(m => m.json.confidence_level === 'very_high').length,
    high: finalMessages.filter(m => m.json.confidence_level === 'high').length,
    medium: finalMessages.filter(m => m.json.confidence_level === 'medium').length,
    low: finalMessages.filter(m => m.json.confidence_level === 'low').length,
    very_low: finalMessages.filter(m => m.json.confidence_level === 'very_low').length
  },

  // إحصائيات الاكتمال
  completeness: {
    complete: finalMessages.filter(m => m.json.is_complete).length,
    partial: finalMessages.filter(m => !m.json.is_complete).length,
    average_score: Math.round(
      finalMessages.reduce((sum, m) => sum + (m.json.completeness_score || 0), 0) / 
      finalMessages.length
    )
  },

  // إحصائيات الاستجابة
  response_stats: {
    should_respond: finalMessages.filter(m => m.json.should_respond).length,
    no_response: finalMessages.filter(m => !m.json.should_respond).length,
    response_types: {
      ai_response: finalMessages.filter(m => m.json.response_strategy.type.includes('ai')).length,
      bot_response: finalMessages.filter(m => m.json.response_strategy.type === 'bot_response').length,
      human_escalation: finalMessages.filter(m => m.json.response_strategy.type === 'human_escalation').length,
      welcome: finalMessages.filter(m => m.json.response_strategy.type.includes('welcome')).length,
      queue: finalMessages.filter(m => m.json.response_strategy.type.includes('queue')).length
    }
  }
};

// طباعة الإحصائيات
console.log('');
console.log('=== Enhanced Processing Statistics ===');
console.log('═══════════════════════════════════════');
console.log(`📊 Total groups processed: ${stats.total_groups}`);
console.log(`📝 Final messages: ${stats.final_messages}`);
console.log('');
console.log('📄 Text Statistics:');
console.log(`  ✓ Valid texts: ${stats.text_stats.valid}`);
console.log(`  ✗ Invalid texts: ${stats.text_stats.invalid}`);
console.log(`  🔄 Merged texts: ${stats.text_stats.merged}`);
console.log(`  Quality breakdown:`, stats.text_stats.quality);
console.log('');
console.log('🎯 Priority Breakdown:', stats.priority_breakdown);
console.log('🤖 Intervention Types:', stats.intervention_breakdown);
console.log('📊 Confidence Levels:', stats.confidence_breakdown);
console.log('');
console.log('✅ Completeness:');
console.log(`  Complete: ${stats.completeness.complete}`);
console.log(`  Partial: ${stats.completeness.partial}`);
console.log(`  Average score: ${stats.completeness.average_score}%`);
console.log('');
console.log('💬 Response Statistics:');
console.log(`  Should respond: ${stats.response_stats.should_respond}`);
console.log(`  No response needed: ${stats.response_stats.no_response}`);
console.log(`  Response types:`, stats.response_stats.response_types);
console.log('═══════════════════════════════════════');

// تحذيرات مهمة
if (stats.text_stats.invalid === stats.final_messages && stats.final_messages > 0) {
  console.warn('');
  console.warn('⚠️ ════ WARNING ════ ⚠️');
  console.warn('All messages have invalid or no text content!');
  console.warn('Common issues found:', 
    finalMessages.map(m => m.json.debug_info.text_validation_reason)
      .filter((v, i, a) => a.indexOf(v) === i)
      .join(', ')
  );
  console.warn('Please check webhook data structure and extraction paths.');
  console.warn('════════════════════');
}

if (stats.confidence_breakdown.very_low > stats.final_messages * 0.5) {
  console.warn('');
  console.warn('⚠️ More than 50% of messages have very low confidence!');
  console.warn('Consider reviewing data quality and extraction logic.');
}

// معلومات إضافية للـ debugging إذا لزم
if (CONFIG.DEBUG_MODE && finalMessages.length > 0) {
  console.log('');
  console.log('🔍 Sample Debug Info (First Message):');
  const sample = finalMessages[0].json.debug_info;
  console.log(`  Event types: ${sample.event_types_found.join(', ')}`);
  console.log(`  Conversation type: ${sample.conversation_type}`);
  console.log(`  Text quality: ${sample.text_quality}`);
  console.log(`  Completeness: ${sample.completeness_score}%`);
  console.log(`  Ready for next: ${sample.ready_for_next_step}`);
}

return finalMessages;
